import Foundation
import CryptoKit

class Transaction {
    var id: Int
    var date: Date
    var type: String // income or expense
    var amount: Double
    var description: String
    
    init(id: Int, date: Date, type: String, amount: Double, description: String) {
        self.id = id
        self.date = date
        self.type = type
        self.amount = amount
        self.description = description
    }
}

class Account {
    var balance: Double = 0.0
    var transactions: [Transaction] = []
    
    func deposit(amount: Double) {
        balance += amount
        let transaction = Transaction(id: transactions.count + 1, date: Date(), type: "income", amount: amount, description: "Deposit")
        transactions.append(transaction)
    }
    
    func withdraw(amount: Double) {
        if balance >= amount {
            balance -= amount
            let transaction = Transaction(id: transactions.count + 1, date: Date(), type: "expense", amount: amount, description: "Withdrawal")
            transactions.append(transaction)
        } else {
            print("Insufficient funds")
        }
    }
}

class BankingApp {
    var accounts: [Account] = []
    
    func createAccount() -> Account {
        let account = Account()
        accounts.append(account)
        return account
    }
    
    func login(username: String, password: String) -> Bool {
        if username == "admin" && password == "password123" {
