    func encryptData(data: String) -> Data? {
        do {
            let encryptedData = try Data(contentsOf: URL(string: data)!)
            return encryptedData
        } catch {
            print("Error encrypting data")
            return nil
        }
    }
    
    func decryptData(data: Data?) -> String? {
        if let data = data {
            do {
