func getTransactionFee(amount: Double) -> Double {
    var fee: Double
    
    switch amount {
    case 0...100:
        fee = 1.00
    case 101...500:
        fee = 2.50
    default:
        fee = 5.00
    }
    
    return fee
}

func calculateAccountBalance(account: Account) -> Double {
    let transactionFees = account.transactions.map { getTransactionFee(amount: $0.amount) }.reduce(0, +)
    return account.balance - transactionFees
}